import SpotifyPlayer from "react-spotify-web-playback";

export const SongPlayer = ({ accessToken, trackURI }) => {
	if (!accessToken) return null;

	return (
		//<div className="song-player">
		<SpotifyPlayer
			token={accessToken}
			showSaveIcon
			autoPlay
			magnifySliderOnHover
			uris={trackURI ? [trackURI] : []}
            
		/>
		//</div>
	);
};
